import os

def create_files():
    files = {
        "backend/app/agents/impl/agents.py": "from app.agents.core.base import AgentBase\nfrom app.agents.core.state import SharedContext\nimport json\n\nclass InputValidationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"InputValidationAgent\")\n    @property\n    def prompt(self): return \"Validate and normalize the input URL.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        context.normalized_url = context.original_target.lower().strip()\n        if \"?\" in context.normalized_url:\n            context.normalized_url = context.normalized_url.split(\"?\")[0] # Strip trackers\n        return context\n\nclass QRProcessingAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"QRProcessingAgent\")\n    @property\n    def prompt(self): return \"Validate the QR payload extraction.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        if context.scan_type == \"QR\" and not context.normalized_url:\n            context.normalized_url = context.original_target\n        return context\n\nclass SecurityAnalysisAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"SecurityAnalysisAgent\")\n    @property\n    def prompt(self): return \"Perform deep technical SSL, WHOIS, and DNS analysis.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        # Mock technical findings for the capstone ADK demonstration\n        context.ssl_valid = True\n        context.whois_age_days = 5\n        context.threat_intel_flags = [\"Flagged by VirusTotal\", \"Recent domain registration\"]\n        return context\n\nclass BrandVerificationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"BrandVerificationAgent\")\n    @property\n    def prompt(self): return \"Detect typosquatting and brand impersonation.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        if \"paypa\" in (context.normalized_url or \"\"):\n            context.impersonated_brand = \"PayPal\"\n            context.official_url = \"https://www.paypal.com\"\n        return context\n\nclass RiskAssessmentAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"RiskAssessmentAgent\")\n    @property\n    def prompt(self): return \"Calculate final risk score based on aggregated findings.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        score = 0\n        if context.whois_age_days and context.whois_age_days < 30:\n            score += 40\n        if context.impersonated_brand:\n            score += 50\n        if context.threat_intel_flags:\n            score += 10\n            \n        context.risk_score = min(score, 100)\n        context.risk_level = \"Critical\" if context.risk_score > 75 else \"High\" if context.risk_score > 50 else \"Low\"\n        context.confidence = 92.5\n        return context\n\nclass ExplanationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"ExplanationAgent\")\n    @property\n    def prompt(self): return \"Convert technical findings into plain English.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        context.explanations = [\n            \"The domain was registered very recently, which is highly suspicious.\",\n            f\"This site appears to be impersonating {context.impersonated_brand}.\"\n        ] if context.impersonated_brand else [\"This site appears safe based on our checks.\"]\n        context.cyber_tip = \"Always double-check the URL in your browser address bar.\"\n        return context\n\nclass RecommendationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"RecommendationAgent\")\n    @property\n    def prompt(self): return \"Generate actionable safety recommendations.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        if context.risk_score and context.risk_score > 50:\n            context.recommendations = [\"Do not enter any personal information.\", \"Close the tab immediately.\"]\n        else:\n            context.recommendations = [\"Proceed with normal caution.\"]\n        return context\n\nclass OfficialWebsiteVerificationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"OfficialWebsiteVerificationAgent\")\n    @property\n    def prompt(self): return \"Find the true verified official website.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        if not context.official_url and context.impersonated_brand:\n            context.official_url = f\"https://www.{context.impersonated_brand.lower()}.com\"\n        return context\n\nclass ReportGenerationAgent(AgentBase):\n    def __init__(self):\n        super().__init__(\"ReportGenerationAgent\")\n    @property\n    def prompt(self): return \"Generate structured final JSON payload.\"\n    async def execute(self, context: SharedContext) -> SharedContext:\n        # Final payload aggregation\n        context.raw_report = json.dumps({\n            \"target\": context.original_target,\n            \"risk\": context.risk_score,\n            \"level\": context.risk_level,\n            \"explanations\": context.explanations\n        })\n        return context\n",
        "backend/app/services/scan_service.py": "from sqlalchemy.ext.asyncio import AsyncSession\nfrom app.schemas.scan import URLScanRequest, QRScanRequest\nfrom app.models.scan import Scan\nfrom app.models.details import ThreatResult, Recommendation, OfficialWebsite\nfrom app.agents.core.state import SharedContext\nfrom app.agents.core.orchestrator import DAGOrchestrator\nfrom app.agents.impl.agents import (\n    InputValidationAgent, QRProcessingAgent, SecurityAnalysisAgent, \n    BrandVerificationAgent, RiskAssessmentAgent, ExplanationAgent, \n    RecommendationAgent, OfficialWebsiteVerificationAgent, ReportGenerationAgent\n)\n\n# Configure DAG Orchestrator\norchestrator = DAGOrchestrator({\n    \"Phase_1_Ingestion\": [InputValidationAgent(), QRProcessingAgent()],\n    \"Phase_2_Analysis\": [SecurityAnalysisAgent(), BrandVerificationAgent()],\n    \"Phase_3_Assessment\": [RiskAssessmentAgent(), OfficialWebsiteVerificationAgent()],\n    \"Phase_4_Synthesis\": [ExplanationAgent(), RecommendationAgent()],\n    \"Phase_5_Reporting\": [ReportGenerationAgent()]\n})\n\nclass ScanService:\n    @staticmethod\n    async def _execute_workflow(db: AsyncSession, target: str, scan_type: str, user_id: int | None = None):\n        # 1. Create Initial State\n        context = SharedContext(original_target=target, scan_type=scan_type)\n        \n        # 2. Run ADK Multi-Agent Orchestrator\n        final_state = await orchestrator.run(context)\n        \n        # 3. Map to Relational Database Models\n        scan = Scan(\n            target=final_state.original_target,\n            scan_type=scan_type,\n            status=\"completed\",\n            risk_score=final_state.risk_score,\n            risk_level=final_state.risk_level,\n            confidence_score=final_state.confidence,\n            user_id=user_id\n        )\n        db.add(scan)\n        await db.flush() # Get scan.id\n        \n        # Add relations\n        for flag in final_state.threat_intel_flags:\n            db.add(ThreatResult(scan_id=scan.id, agent_name=\"ThreatIntelAgent\", status=\"Fail\", description=flag, passed=False))\n            \n        for rec in final_state.recommendations:\n            db.add(Recommendation(scan_id=scan.id, text=rec, priority=\"High\"))\n            \n        if final_state.impersonated_brand:\n            db.add(OfficialWebsite(scan_id=scan.id, brand_name=final_state.impersonated_brand, official_url=final_state.official_url or \"\"))\n            \n        await db.commit()\n        \n        # 4. Return formatted JSON response\n        return {\n            \"id\": scan.id,\n            \"target\": scan.target,\n            \"scan_type\": scan.scan_type,\n            \"status\": scan.status,\n            \"risk_score\": scan.risk_score,\n            \"risk_level\": scan.risk_level,\n            \"created_at\": str(scan.created_at)\n        }\n\n    @staticmethod\n    async def process_url_scan(db: AsyncSession, scan_req: URLScanRequest):\n        return await ScanService._execute_workflow(db, str(scan_req.target_url), \"URL\")\n\n    @staticmethod\n    async def process_qr_scan(db: AsyncSession, scan_req: QRScanRequest):\n        return await ScanService._execute_workflow(db, scan_req.qr_data, \"QR\")\n"
    }

    for path, content in files.items():
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)

if __name__ == "__main__":
    create_files()
    print("Backend Stage 7 Part 2 scaffolded.")
